test_cases.python_test_script:
def test_tc_gw_spd_001_present(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs, 'GW_VehicleSpeed not detected'

def test_tc_gw_spd_002_zero(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_vehicle_speed_kmph(msg.data) == 0.0

def test_tc_gw_spd_003_low(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_vehicle_speed_kmph(msg.data) == 10.0

def test_tc_gw_spd_004_mid(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_vehicle_speed_kmph(msg.data) == 60.0

def test_tc_gw_spd_005_max(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_vehicle_speed_kmph(msg.data) == 250.0

def test_tc_gw_spd_006_periodic(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert len(msgs) >= 3

def test_tc_gw_spd_007_constant(can_bus):
    msgs = collect_gw_messages(can_bus, 3.0)
    assert msgs
    first = get_vehicle_speed_kmph(msgs[0].data)
    for msg in msgs:
        assert get_vehicle_speed_kmph(msg.data) == first

def test_tc_gw_spd_008_dlc(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_VEHICLE_SPEED_DLC
